promise.then(value => {
  console.log("Fulfilled with:", value);
});

function fetchUser(id) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (id <= 0) {
        reject(new Error(`Invalid ID: ${id}`));
      } else {
        resolve({ id, name: `User${id}`, role: 'user' });
      }
    }, 100); // simulates 100ms network delay
  });
}

console.log("Fetching user...");
fetchUser(1).then(user => console.log("Got:", user.name));
console.log("This runs before the user arrives!");

function fetchUser(id) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (id > 0) resolve({ id, name: `User${id}` });
      else reject(new Error(`Invalid ID: ${id}`));
    }, 50);
  });
}

fetchUser(5)
  .then(user => console.log("User:", user.name))
  .catch(err => console.log("Error:", err.message));

fetchUser(-1)
  .then(user => console.log("User:", user.name))
  .catch(err => console.log("Error:", err.message));

function delay(ms, value) {
  return new Promise(resolve => setTimeout(() => resolve(value), ms));
}

delay(50, { id: 1, name: "alex", score: 78 })
  .then(user => {
    console.log("Step 1 - Got user:", user.name);
    return user.name; // pass name to next then
  })
  .then(name => {
    console.log("Step 2 - Name:", name);
    return name.toUpperCase();
  })
  .then(upper => {
    console.log("Step 3 - Uppercased:", upper);
  })
  .catch(err => console.log("Error:", err.message));

let isLoading = true;
console.log("Loading:", isLoading);

function fetchData(shouldFail) {
  return new Promise((resolve, reject) => {
    setTimeout(() => shouldFail ? reject(new Error("Failed!")) : resolve("Data!"), 50);
  });
}

fetchData(false)
  .then(data => console.log("Success:", data))
  .catch(err => console.log("Error:", err.message))
  .finally(() => {
    isLoading = false;
    console.log("Loading:", isLoading);
  });

fetchData(true)
  .then(data => console.log("Success:", data))
  .catch(err => console.log("Error:", err.message))
  .finally(() => console.log("Done (either way)."));

function fakeRequest(name, ms, shouldFail = false) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      shouldFail ? reject(new Error(`${name} failed`)) : resolve(`${name} data`);
    }, ms);
  });
}

const start = Date.now();
Promise.all([
  fakeRequest("users",    100),
  fakeRequest("products", 150),
  fakeRequest("orders",   80),
])
  .then(([users, products, orders]) => {
    const elapsed = Date.now() - start;
    console.log(users);
    console.log(products);
    console.log(orders);
    console.log(`Took ~${Math.round(elapsed/100)*100}ms (parallel)`);  // ~150ms, not 330ms
  });

function fakeRequest(name, ms, fail = false) {
  return new Promise((res, rej) => setTimeout(() => fail ? rej(new Error(`${name} error`)) : res(`${name} ok`), ms));
}

Promise.allSettled([
  fakeRequest("users",    50),
  fakeRequest("orders",   80, true), // this one fails
  fakeRequest("products", 60),
])
  .then(results => {
    results.forEach(r => {
      if (r.status === "fulfilled") console.log("✓", r.value);
      else                          console.log("✗", r.reason.message);
    });
  });

function withTimeout(promise, ms) {
  const timer = new Promise((_, reject) =>
    setTimeout(() => reject(new Error(`Timeout after ${ms}ms`)), ms)
  );
  return Promise.race([promise, timer]);
}

function slowRequest(ms) {
  return new Promise(resolve => setTimeout(() => resolve("Data!"), ms));
}

withTimeout(slowRequest(100), 500)
  .then(d => console.log("Fast enough:", d))
  .catch(e => console.log(e.message));

withTimeout(slowRequest(1000), 300)
  .then(d => console.log("Fast enough:", d))
  .catch(e => console.log(e.message));
